import React, { useEffect, useState } from 'react';
import "./index.css";
import { Form, Input, Button, Layout, Row, Col, Card, Space } from 'antd';
import Api from '../../helpers/api';
import { connect } from 'react-redux';
import { setUser } from '../../redux/actions/setUserAction';
import store from "../../redux/store";
import { message } from "antd";

const api = new Api();

const Login = (props) => {

    const [errors, setErrors] = useState({})
    const [isLoading, setIsLoading] = useState(false)

    useEffect(() => {

    })

    const [form] = Form.useForm();

    const onFinish = (value) => {

        const { email, password } = value

        setIsLoading(true)
        api.login(email, password)
            .then(response => {
                setIsLoading(false)
                if (response.status === 200) { //OK
                    try {
                        let user = response.data
                        let token = user.token
                        store.dispatch(setUser(user))

                        localStorage.setItem('user', JSON.stringify(user));
                        localStorage.setItem('api_token', token);
                        props.history.push('/')
                    } catch (error) {
                        console.log('Error save user data', error)
                    }
                }
            })
            .catch(error => {
                setIsLoading(false)
                if (error.response && error.response.data) {
                    const { errors } = error.response.data
                    setErrors(errors)
                    message.error(error.response.data.message);
                }
            });

    };

    const formItemLayout = {
        labelCol: {
            md: { span: 8 },
        },
        wrapperCol: {
            md: { span: 16 },
        },
    };

    return (
        <div className="login-form-wrapper">
            <Row type="flex" justify="center" align="middle" style={{ minHeight: '100vh' }}>
                <Card>
                    <Form form={form} onFinish={onFinish} {...formItemLayout}>

                        <Form.Item name="email" label="Email"
                            validateStatus={errors && errors.email ? 'error' : undefined}
                            help={errors ? errors.email : null}
                            rules={[{ required: false, message: 'Please input email' }]}
                        >
                            <Input />
                        </Form.Item>

                        <Form.Item name="password" label="Password"
                            validateStatus={errors && errors.password ? 'error' : undefined}
                            help={errors ? errors.password : null}
                            rules={[{ required: false, message: 'Please input password' }]}
                        >
                            <Input.Password />
                        </Form.Item>

                        <center>
                            <Button type="primary" htmlType="submit"
                                loading={isLoading}>
                                Login
                            </Button>
                        </center>

                    </Form>
                </Card>
            </Row>
        </div>
    )
}

export default connect(
    null,
    { setUser }
)(Login);
